import React, { useEffect, useState } from 'react'; 
import './Atendimento.css'; 

const Atendimento = () => {
  const [atendimentos, setAtendimentos] = useState([]);

  useEffect(() => {
    const fetchAtendimentos = async () => {
      try {
        const response = await fetch('/api/atendimentos'); // Modifique a URL conforme necessário
        const data = await response.json();
        setAtendimentos(data);
      } catch (error) {
        console.error('Erro ao buscar atendimentos:', error);
      }
    };

    fetchAtendimentos();
  }, []); // O array vazio significa que isso só acontece na montagem do componente.

  return (
    <div className="atendimento-container">
      <h1>Atendimentos</h1>
      <table className="atendimento-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Nome</th>
            <th>Status</th>
            <th>Data</th>
          </tr>
        </thead>
        <tbody>
          {atendimentos.map((atendimento) => (
            <tr key={atendimento.id}>
              <td>{atendimento.id}</td>
              <td>{atendimento.nome}</td>
              <td>{atendimento.status}</td>
              <td>{atendimento.data}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Atendimento;
